// ─── Helper functions ────────────────────────────────────────────────────────

// Days from start date
PD.di=function(dt){
  var s=new Date(PD.start+'T00:00:00Z');
  return Math.round((Date.UTC(dt.getFullYear(),dt.getMonth(),dt.getDate())-s.getTime())/(86400000));
};

// All sidereal planet longitudes for a date
// Returns {sun,moon,mars,jup,sat,ven,mer,rahu,ketu} in degrees
PD.geo=function(dt){
  var i=PD.di(dt);
  if(i<0||i>=PD.p.length)return null;
  var row=PD.p[i];
  return{sun:row[0],moon:row[1],mars:row[2],jup:row[3],
         sat:row[4],ven:row[5],mer:row[6],rahu:row[7],ketu:(row[7]+180)%360};
};

// Moon sidereal longitude at specific hour (0-23) IST via 6h interpolation
PD.moonAt=function(dt,hIST){
  var i=PD.di(dt);
  var hUT=hIST-5.5;
  if(hUT<0){i--;hUT+=24;}
  var idx6=i*4+hUT/6;
  var i6=Math.floor(idx6),f=idx6-i6;
  if(i6<0)return PD.m6[0];
  if(i6>=PD.m6.length-1)return PD.m6[PD.m6.length-1];
  var l0=PD.m6[i6],l1=PD.m6[i6+1];
  var d=l1-l0;if(d>180)d-=360;if(d<-180)d+=360;
  return(l0+f*d+360)%360;
};

// Lahiri Ayanamsa (Bishuddha Siddhanta calibrated)
PD.ay=function(jd){
  var T=(jd-2451545)/36525;
  return 23.819167+1.548210*T;
};

// Sunrise & Sunset for date (decimal hours IST)
PD.sun=function(dt){
  var i=PD.di(dt);
  if(i<0||i>=PD.r.length)return{rise:6,set:18};
  return{rise:PD.r[i],set:PD.s[i]};
};

// ════════════════════════════════════════════════════════════════════════════
// পঞ্চাঙ্গ গণনা ইঞ্জিন — JPL DE441 ভিত্তিক (বিশুদ্ধ সিদ্ধান্ত পদ্ধতি)
// স্থান: কলকাতা (LAT=22.5833°N, LNG=88.3767°E, IST=+5.5h)
// ════════════════════════════════════════════════════════════════════════════

// JD (UT) → {dt: Date (UTC midnight of IST calendar date), h: IST hour (0-24)}
PD.jdIST=function(jd){
  var istJD=jd+5.5/24;
  var istDayFrac=istJD+0.5;
  var istDay=Math.floor(istDayFrac);
  var h=(istDayFrac-istDay)*24;
  var Z=istDay;
  if(Z>=2299161){var al=Math.floor((Z-1867216.25)/36524.25);Z=Z+1+al-Math.floor(al/4);}
  var B=Z+1524,C=Math.floor((B-122.1)/365.25),D=Math.floor(365.25*C),E=Math.floor((B-D)/30.6001);
  var day=B-D-Math.floor(30.6001*E);
  var month=E<14?E-1:E-13;
  var year=month>2?C-4716:C-4715;
  return{dt:new Date(Date.UTC(year,month-1,day)),h:h};
};

// সূর্যের সিদ্ধান্তীয় দ্রাঘিমা (JPL DE441 — UT-aligned linear interpolation)
// PD.p[i] ডেটা 0h UT (UT মধ্যরাত) = IST 5:30h এ সংগ্রহ করা
// moonAt()-এর মতো UT-ভিত্তিক fraction ব্যবহার করতে হবে
PD.sunSid=function(jd){
  var ist=PD.jdIST(jd);
  if(!ist)return null;
  // UT hour থেকে সঠিক day index ও fraction বের করা
  var hUT=ist.h-5.5; // IST থেকে UT-এ রূপান্তর
  var dayOff=0;
  if(hUT<0){hUT+=24;dayOff=-1;} // UT মধ্যরাতের আগে = আগের দিনের ডেটা
  var i0=PD.di(ist.dt)+dayOff;
  if(i0<0||i0+1>=PD.p.length){
    // Fallback: Meeus simplified
    var n=jd-2451545,L=((280.46+0.9856474*n)%360+360)%360,g2=((357.528+0.9856003*n)%360+360)*Math.PI/180;
    var lam=L+1.915*Math.sin(g2)+0.02*Math.sin(2*g2);
    var T=(jd-2451545)/36525,ay=23.819167+1.548210*T;
    return((lam-ay)%360+360)%360;
  }
  var s0=PD.p[i0][0],s1=PD.p[i0+1][0];
  var d=s1-s0;if(d>180)d-=360;if(d<-180)d+=360;
  return(s0+hUT/24*d+360)%360;
};

// চন্দ্রের সিদ্ধান্তীয় দ্রাঘিমা (6-hourly PD data থেকে)
PD.moonSid=function(jd){
  var ist=PD.jdIST(jd);
  return PD.moonAt(ist.dt,ist.h);
};

// সমস্ত গ্রহের সিদ্ধান্তীয় দ্রাঘিমা {sun,moon,mars,jup,sat,ven,mer,rahu,ketu}
// PD.geo() একদিনের সরাসরি JPL data; গ্রহগুলো slow তাই daily interpolation যথেষ্ট
PD.allPlanets=function(jd){
  var ist=PD.jdIST(jd);
  var g0=PD.geo(ist.dt);
  var g1=PD.geo(new Date(ist.dt.getTime()+86400000));
  if(!g0)return null;
  if(!g1)return{sun:g0.sun,moon:PD.moonSid(jd),mars:g0.mars,jup:g0.jup,sat:g0.sat,ven:g0.ven,mer:g0.mer,rahu:g0.rahu,ketu:g0.ketu};
  var frac=ist.h/24;
  function interp(k){var d=g1[k]-g0[k];if(d>180)d-=360;if(d<-180)d+=360;return(g0[k]+frac*d+360)%360;}
  var rahu=interp('rahu');
  return{sun:PD.sunSid(jd),moon:PD.moonSid(jd),mars:interp('mars'),jup:interp('jup'),sat:interp('sat'),ven:interp('ven'),mer:interp('mer'),rahu:rahu,ketu:(rahu+180)%360};
};

// সূর্যোদয় ও সূর্যাস্ত — PD lookup (decimal IST hours)
PD.sunTimes=function(y,m,d){
  var dt=new Date(Date.UTC(y,m-1,d));
  return PD.sun(dt);
};

// তিথি index (0-29) at JD
PD.tithiIdx=function(jd){
  return Math.floor(((PD.moonSid(jd)-PD.sunSid(jd)+360)%360)/12)%30;
};

// নক্ষত্র index (0-26) at JD
PD.nakshatraIdx=function(jd){
  return Math.floor(PD.moonSid(jd)/(360/27))%27;
};

// যোগ index (0-26) at JD
PD.yogaIdx=function(jd){
  return Math.floor(((PD.sunSid(jd)+PD.moonSid(jd))%360)/(360/27))%27;
};

// করণ নম্বর (0-59) at JD
PD.karanaNum=function(jd){
  return Math.floor(((PD.moonSid(jd)-PD.sunSid(jd)+360)%360)/6)%60;
};

// লগ্ন (ascendant) রাশি index (0-11) এবং ডিগ্রি at JD (UT)
// বিশুদ্ধ সিদ্ধান্ত: Lahiri ayanamsha বিয়োগ করা সিদ্ধান্তীয় লগ্ন
PD.lagnaAt=function(jd){
  var T=(jd-2451545)/36525;
  var GMST=((280.46061837+360.98564736629*(jd-2451545)+0.000387933*T*T)%360+360)%360;
  var LST=(GMST+88.3767+360)%360; // Kolkata longitude
  var LSTR=LST*Math.PI/180;
  var eps=(23.439291-0.013004*T)*Math.PI/180;
  var latR=22.5833*Math.PI/180; // Kolkata latitude
  var ascTrop=Math.atan2(Math.cos(LSTR),-Math.sin(LSTR)*Math.cos(eps)-Math.tan(latR)*Math.sin(eps));
  ascTrop=(ascTrop*180/Math.PI+360)%360;
  if(Math.sin(LSTR)>0)ascTrop=(ascTrop+180)%360;
  var ay=23.819167+1.548210*T; // Lahiri ayanamsha
  var lagnaS=(ascTrop-ay+360)%360;
  return{deg:lagnaS,rashi:Math.floor(lagnaS/30)%12,degInRashi:lagnaS%30};
};

// বিংশোত্তরী দশার অধিপতি গ্রহ (nakshatra index 0-26 থেকে)
PD.dashLord=function(nakIdx){
  var lords=['কেতু','শুক্র','সূর্য','চন্দ্র','মঙ্গল','রাহু','গুরু','শনি','বুধ'];
  return lords[nakIdx%9];
};

// রাশির বাংলা নাম
PD.RASHI=['মেষ','বৃষ','মিথুন','কর্কট','সিংহ','কন্যা','তুলা','বৃশ্চিক','ধনু','মকর','কুম্ভ','মীন'];
PD.NAKSHATRA=['অশ্বিনী','ভরণী','কৃত্তিকা','রোহিণী','মৃগশিরা','আর্দ্রা','পুনর্বসু','পুষ্যা','আশ্লেষা','মঘা','পূর্বফাল্গুনী','উত্তরফাল্গুনী','হস্তা','চিত্রা','স্বাতী','বিশাখা','অনুরাধা','জ্যেষ্ঠা','মূলা','পূর্বাষাঢ়া','উত্তরাষাঢ়া','শ্রবণা','ধনিষ্ঠা','শতভিষা','পূর্বভাদ্র','উত্তরভাদ্র','রেবতী'];
PD.LAGNA_NAME=['মেষ লগ্ন','বৃষ লগ্ন','মিথুন লগ্ন','কর্কট লগ্ন','সিংহ লগ্ন','কন্যা লগ্ন','তুলা লগ্ন','বৃশ্চিক লগ্ন','ধনু লগ্ন','মকর লগ্ন','কুম্ভ লগ্ন','মীন লগ্ন'];

// মৃত্যু দোষ গণনা — বিশুদ্ধ সিদ্ধান্ত পঞ্জিকা নিয়ম
// returns: {doshas:[{type,pads,label,endTime}], totalPads, name}
PD.mrityuDosha=function(dow,tithiList,nakList){
  var doshas=[];

  // ১) বার দোষ — রবিবার = একপাদ (সারাদিন)
  // বিশুদ্ধ সিদ্ধান্ত অনুযায়ী রবিবার মৃত্যু বার দোষ
  var BAR_DOSHA={0:'রবি বার',2:'মঙ্গল বার'}; // Sunday=0, Tuesday=2
  if(BAR_DOSHA[dow]!==undefined){
    doshas.push({type:'bar',pads:1,label:BAR_DOSHA[dow]+' দোষ',endTime:null});
  }

  // ২) নক্ষত্র দোষ — নির্দিষ্ট নক্ষত্রে দ্বিপাদ দোষ
  // পঞ্চক নক্ষত্র: ধনিষ্ঠা(22), শতভিষা(23), পূর্বভাদ্র(24), উত্তরভাদ্র(25), রেবতী(26)
  var MRITYU_NAKS=[22,23,24,25,26];
  if(nakList){
    nakList.forEach(function(n){
      if(!n||!n.val)return;
      var nIdx=PD.NAKSHATRA.indexOf(n.val.name);
      if(MRITYU_NAKS.indexOf(nIdx)>=0){
        doshas.push({type:'nakshatra',pads:2,label:'নক্ষত্র দোষ ('+n.val.name+')',endTime:n.endTime||null});
      }
    });
  }

  // ৩) তিথি দোষ — নির্দিষ্ট তিথিতে একপাদ দোষ
  // চতুর্থী(3), অষ্টমী(7), নবমী(8), চতুর্দশী(13), অমাবস্যা(29) = কৃষ্ণপক্ষ
  var MRITYU_TITHIS_KRISHNA=[3,7,8,12,13]; // কৃষ্ণপক্ষ 0-indexed (16=কৃষ্ণপ্রতিপদ → index offset)
  var MRITYU_TITHIS_SHUKLA=[]; // শুক্লপক্ষে সাধারণত তিথি দোষ নেই
  if(tithiList){
    tithiList.forEach(function(t){
      if(!t||!t.val)return;
      var pakDay=t.val.pakDay;
      var isKrishna=(t.val.paksha==='কৃষ্ণপক্ষ');
      var tRaw=(isKrishna?15:0)+(pakDay-1); // 0-29
      // চতুর্থী(3), অষ্টমী(7), নবমী(8), চতুর্দশী(13), অমাবস্যা(29) = সব পক্ষে
      var BAD=[3,7,8,13,29];
      if(BAD.indexOf(tRaw)>=0){
        doshas.push({type:'tithi',pads:1,label:'তিথি দোষ ('+t.val.name+')',endTime:t.endTime||null});
      }
    });
  }

  if(!doshas.length)return null;
  var totalPads=0;
  doshas.forEach(function(x){totalPads+=x.pads;});
  // নামকরণ
  var name;
  if(totalPads>=4)name='মৃত্যু পুষ্কর দোষ';
  else if(totalPads===3)name='মৃত্যু ত্রিপাদ দোষ';
  else if(totalPads===2)name='মৃত্যু দ্বিপাদ দোষ';
  else name='মৃত্যু একপাদ দোষ';
  return{doshas:doshas,totalPads:totalPads,name:name};
};

// অক্ষয় যোগ — বিশুদ্ধ সিদ্ধান্ত পঞ্জিকা নিয়ম
// সোমবার অমাবস্যা, রবিবার শুক্ল সপ্তমী, মঙ্গলবার শুক্ল চতুর্থী, বৃহস্পতি শুক্ল অষ্টমী
PD.akshayaYoga=function(dow,tithiList){
  var RULES=[
    {dow:1,paksha:'কৃষ্ণপক্ষ',pakDay:15,name:'সোমবার অমাবস্যা অক্ষয় যোগ'},
    {dow:0,paksha:'শুক্লপক্ষ',pakDay:7,name:'রবিবার শুক্ল সপ্তমী অক্ষয় যোগ'},
    {dow:2,paksha:'শুক্লপক্ষ',pakDay:4,name:'মঙ্গলবার শুক্ল চতুর্থী অক্ষয় যোগ'},
    {dow:4,paksha:'শুক্লপক্ষ',pakDay:8,name:'বৃহস্পতিবার শুক্ল অষ্টমী অক্ষয় যোগ'}
  ];
  if(!tithiList)return null;
  var found=[];
  RULES.forEach(function(rule){
    if(dow!==rule.dow)return;
    tithiList.forEach(function(t){
      if(!t||!t.val)return;
      if(t.val.paksha===rule.paksha&&t.val.pakDay===rule.pakDay){
        found.push({name:rule.name,endTime:t.endTime||null});
      }
    });
  });
  return found.length?found:null;
};

// দ্বিদণ্ডাত্মক মধ্যরাত্রি নিয়মে মাস-শেষ নির্ধারণ
// ১ দণ্ড = ২৪ মিনিট → দ্বিদণ্ড = ৪৮ মিনিট (মধ্যরাতের ±২৪ মিনিট)
PD.dwidandaMaasShesh=function(y,m,d,bnMonth){
  var jd0=PD._jd(y,m,d); // midnight IST JD
  var rashiStart=Math.floor(PD.sunSid(jd0)/30)%12;
  var sankrantiJD=null;
  for(var i=0;i<1440;i++){
    var jdT=jd0+i/1440;
    if(Math.floor(PD.sunSid(jdT)/30)%12!==rashiStart){
      var lo=jd0+(i-1)/1440,hi=jdT;
      for(var k=0;k<40;k++){var mid=(lo+hi)/2;if(Math.floor(PD.sunSid(mid)/30)%12===rashiStart)lo=mid;else hi=mid;}
      sankrantiJD=(lo+hi)/2;break;
    }
  }
  if(!sankrantiJD)return null;
  var ist=PD.jdIST(sankrantiJD);
  var localH=ist.h;
  var midnight=Math.round(localH/24)*24;
  var diff=Math.abs(localH-midnight);
  if(diff>0.8)return{sankrantiH:localH,inWindow:false};
  var riseH=PD.sunTimes(y,m,d).rise;
  var jdRise=jd0+(riseH-5.5)/24;
  var tAtRise=PD.tithiIdx(jdRise);
  var tAtSankranti=PD.tithiIdx(sankrantiJD);
  var maasSheshDay;
  if(bnMonth===2){maasSheshDay='আজকের দিন (আষাঢ় বিশেষ নিয়ম)';}
  else if(bnMonth===8){maasSheshDay='পরের দিন (পৌষ বিশেষ নিয়ম)';}
  else if(tAtRise===tAtSankranti){maasSheshDay='আজকের দিন (উদয়-তিথি ও সংক্রান্তি-তিথি একই)';}
  else{maasSheshDay='পরের দিন (তিথি পরিবর্তন হয়েছে)';}
  return{sankrantiH:localH,inWindow:true,maasSheshDay:maasSheshDay,tAtRise:tAtRise,tAtSankranti:tAtSankranti};
};

// JD helper — midnight IST এর JD (UT)
PD._jd=function(y,m,d){
  if(m<=2){y--;m+=12;}
  var A=Math.floor(y/100),B=2-A+Math.floor(A/4);
  return Math.floor(365.25*(y+4716))+Math.floor(30.6001*(m+1))+d+B-1524.5-5.5/24;
};
